&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;strong&gt;Corporate Accountant&lt;/strong&gt;&lt;strong&gt; | &lt;/strong&gt;Vienna, Austria&lt;/span&gt;&lt;/p&gt;
